"""
JASON - Local AI Avatar Chatbot with SadTalker Integration
Real lip-sync video from your character.jpg using SadTalker.

SETUP:
  1. Install SadTalker:
     git clone https://github.com/OpenTalker/SadTalker
     cd SadTalker && pip install -r requirements.txt
     python scripts/download_models.py
  2. Run this file: python ai_chatbot.py

Without SadTalker: falls back to CSS animated avatar automatically.
"""
import os, asyncio, base64, subprocess, shutil
from pathlib import Path
import gradio as gr

_GR_MAJOR = int(gr.__version__.split(".")[0])

# ── Avatar image ─────────────────────────────────────────────────────────────
_AVATAR_PATH = Path("assets/character.jpg")
if _AVATAR_PATH.exists():
    with open(_AVATAR_PATH, "rb") as _f:
        AVATAR_B64 = base64.b64encode(_f.read()).decode()
else:
    AVATAR_B64 = ""

# =============================================================================
# SADTALKER INTEGRATION
# =============================================================================
class SadTalker:
    """
    Wraps SadTalker to generate real lip-sync video from a still image + audio.
    Finds SadTalker automatically in common locations.
    Falls back to None so the UI degrades gracefully.
    """
    SEARCH_PATHS = [
        Path.cwd() / "SadTalker",
        Path.cwd() / "sadtalker",
        Path.home() / "SadTalker",
        Path.home() / "sadtalker",
        Path("C:/SadTalker"),
        Path("C:/sadtalker"),
    ]
    def __init__(self):
        self.path = self._find()
        self.tmp  = Path("temp_sadtalker"); self.tmp.mkdir(exist_ok=True)
        if self.path:
            print(f"✅ SadTalker found at: {self.path}")
        else:
            print("⚠  SadTalker not found — using CSS animated avatar.")
            print("   To enable real lip-sync:")
            print("   git clone https://github.com/OpenTalker/SadTalker")
            print("   cd SadTalker && pip install -r requirements.txt")
            print("   python scripts/download_models.py")

    def _find(self):
        for p in self.SEARCH_PATHS:
            if p.exists() and (p / "inference.py").exists():
                return str(p)
        return None

    @property
    def available(self): return self.path is not None

    def generate(self, image_path: str, audio_path: str) -> str | None:
        """
        Generate a lip-sync video using SadTalker.
        Returns path to output .mp4, or None on failure.
        """
        if not self.available: return None
        if not os.path.exists(image_path):
            print(f"SadTalker: image not found: {image_path}"); return None
        if not audio_path or not os.path.exists(audio_path):
            print("SadTalker: audio not found"); return None

        out_dir = str(self.tmp / f"run_{os.urandom(4).hex()}")
        os.makedirs(out_dir, exist_ok=True)

        cmd = [
            "python", os.path.join(self.path, "inference.py"),
            "--driven_audio",  audio_path,
            "--source_image",  image_path,
            "--result_dir",    out_dir,
            "--still",          # less head movement — better for portrait
            "--preprocess",    "full",   # full face, not crop
            "--enhancer",      "gfpgan", # sharpen face quality
        ]

        # If no GPU, add cpu flag
        try:
            import torch
            if not torch.cuda.is_available():
                cmd += ["--cpu"]
        except ImportError:
            cmd += ["--cpu"]

        print(f"🎬 SadTalker generating video... (this takes 15-60s on CPU)")
        try:
            result = subprocess.run(
                cmd, cwd=self.path,
                capture_output=True, text=True, timeout=300)
            if result.returncode != 0:
                print(f"SadTalker error:\n{result.stderr[-800:]}")
                return None
            # Find the generated .mp4
            videos = list(Path(out_dir).rglob("*.mp4"))
            if videos:
                out = str(videos[0])
                print(f"✅ Video generated: {out}")
                return out
            print("SadTalker: no video found in output")
            return None
        except subprocess.TimeoutExpired:
            print("SadTalker: timed out (>5 min)"); return None
        except Exception as e:
            print(f"SadTalker error: {e}"); return None

    def cleanup(self, keep=3):
        """Remove old runs keeping the N most recent."""
        dirs = sorted(self.tmp.glob("run_*"),
                      key=lambda d: d.stat().st_mtime, reverse=True)
        for d in dirs[keep:]:
            shutil.rmtree(d, ignore_errors=True)

# =============================================================================
# SENTIMENT
# =============================================================================
_POS = {"good","great","happy","love","excellent","amazing","wonderful",
        "fantastic","awesome","nice","glad","thanks","cool","yes","excited","fun","enjoy","joy"}
_NEG = {"bad","sad","hate","terrible","awful","horrible","worst","angry",
        "upset","wrong","no","not","never","problem","fail","broken","worried","pain"}

class SentimentAnalyzer:
    def __init__(self): self._model=None; self._tried=False
    def _load(self):
        if self._tried: return
        self._tried=True
        try:
            import torch,transformers
            self._model=transformers.pipeline(
                "sentiment-analysis",
                model="distilbert-base-uncased-finetuned-sst-2-english",
                device=0 if torch.cuda.is_available() else -1)
            print("✅ Sentiment model loaded")
        except Exception as e: print(f"Sentiment fallback: {e}")
    def analyze(self,text):
        if not text: return {"label":"neutral","score":0.5,"emotion":"calm"}
        self._load()
        if self._model:
            try:
                r=self._model(text[:512])[0]
                lbl=r["label"].lower()
                em={"positive":"happy","negative":"sad"}.get(lbl,"calm")
                return {"label":lbl,"score":float(r["score"]),"emotion":em}
            except: pass
        words=set(text.lower().split())
        p,n=len(words&_POS),len(words&_NEG)
        if p>n: return {"label":"positive","score":0.8,"emotion":"happy"}
        if n>p: return {"label":"negative","score":0.8,"emotion":"sad"}
        return         {"label":"neutral","score":0.5,"emotion":"calm"}
    def get_emotion(self,user_text,ai_reply=""):
        s=self.analyze(user_text)
        if ai_reply:
            if s["label"]=="negative": return "empathetic"
            if s["label"]=="positive": return "excited"
        return s["emotion"]
    def get_emotion_for_response(self,u,a=""): return self.get_emotion(u,a)

# =============================================================================
# TTS
# =============================================================================
class TTSGenerator:
    VOICES={"happy":"en-US-JennyNeural","excited":"en-US-JennyNeural",
            "sad":"en-US-AriaNeural","empathetic":"en-US-AriaNeural",
            "calm":"en-US-AriaNeural","confident":"en-US-GuyNeural",
            "concerned":"en-US-AriaNeural","thoughtful":"en-US-AriaNeural"}
    RATES={"excited":"+15%","happy":"+8%","calm":"+0%","sad":"-10%",
           "empathetic":"-5%","thoughtful":"-5%","confident":"+5%","concerned":"-3%"}
    def __init__(self):
        self.tmp=Path("temp_audio"); self.tmp.mkdir(exist_ok=True)
    async def _gen(self,text,voice,rate,path):
        import edge_tts
        await edge_tts.Communicate(text,voice,rate=rate).save(path)
    def generate_audio(self,text,emotion="calm"):
        if not text: return None
        voice=self.VOICES.get(emotion,"en-US-AriaNeural")
        rate=self.RATES.get(emotion,"+0%")
        path=str(self.tmp/f"tts_{os.urandom(4).hex()}.mp3")
        try:
            try:
                asyncio.get_running_loop()
                import concurrent.futures
                with concurrent.futures.ThreadPoolExecutor() as pool:
                    pool.submit(asyncio.run,self._gen(text,voice,rate,path)).result()
            except RuntimeError:
                asyncio.run(self._gen(text,voice,rate,path))
            return path if os.path.exists(path) else None
        except Exception as e:
            print(f"TTS error: {e}"); return None
    def generate(self,t,e="calm"): return self.generate_audio(t,e)

# =============================================================================
# STT
# =============================================================================
class VoiceRecognizer:
    def __init__(self):
        import speech_recognition as sr
        self.r=sr.Recognizer()
    def transcribe_from_file(self,a): return self.transcribe(a)
    def transcribe(self,audio):
        import speech_recognition as sr
        if audio is None: return ""
        path=audio[0] if isinstance(audio,tuple) else audio
        if not path: return ""
        try:
            with sr.AudioFile(str(path)) as src:
                self.r.adjust_for_ambient_noise(src,duration=0.2)
                data=self.r.record(src)
            return self.r.recognize_google(data).strip()
        except sr.UnknownValueError: return ""
        except Exception as e: return f"Error: {e}"

# =============================================================================
# LLM
# =============================================================================
class AIChatbot:
    SYSTEM=("You are JASON, a warm helpful AI assistant. "
            "Respond naturally, concisely in 1-3 sentences. "
            "Match the emotional tone of the conversation.")
    def __init__(self,character_image_path="assets/character.jpg",model_name="llama3.2"):
        self.sentiment=SentimentAnalyzer()
        self.character_path=os.path.abspath(character_image_path)
        self.chat_history=[]
        self.model_name=model_name
        os.makedirs("assets",exist_ok=True)
    def get_ai_response(self,message):
        try: import ollama
        except ImportError: return "Install ollama then run: ollama serve"
        msgs=[{"role":"system","content":self.SYSTEM}]+self.chat_history[-10:]
        msgs.append({"role":"user","content":message})
        try:
            r=ollama.chat(model=self.model_name,messages=msgs)
            reply=r["message"]["content"]
            self.chat_history+=[{"role":"user","content":message},{"role":"assistant","content":reply}]
            return reply
        except Exception as e: return f"Ollama error: {e}"

