# =============================================================================
# AVATAR HTML  (CSS animated fallback — used when SadTalker not available)
# =============================================================================
GLOW={"happy":"#4CAF50","excited":"#FF9800","sad":"#607D8B",
      "empathetic":"#E91E63","calm":"#00BCD4","confident":"#9C27B0",
      "concerned":"#795548","thoughtful":"#3F51B5","professional":"#37474F"}
ELABEL={"happy":"😊 Happy","excited":"🤩 Excited","sad":"😔 Sad",
        "empathetic":"🤗 Empathetic","calm":"😌 Calm","confident":"💪 Confident",
        "concerned":"😟 Concerned","thoughtful":"🤔 Thoughtful","professional":"👔 Professional"}
SLABEL={"idle":"● Ready","listening":"🎤 Listening…",
        "thinking":"⏳ Thinking…","talking":"💬 Speaking…",
        "rendering":"🎬 Rendering lip-sync…"}

def make_avatar_html(emotion="calm",state="idle"):
    gw=GLOW.get(emotion,"#00BCD4")
    el=ELABEL.get(emotion,"😌 Calm")
    sl=SLABEL.get(state,"● Ready")
    rv=int(gw[1:3],16); gv=int(gw[3:5],16); bv=int(gw[5:7],16)
    pulse=""
    if state in ("talking","listening","rendering"):
        pulse=('<div style="position:absolute;inset:-14px;border-radius:50% 50% 42% 42%;'
               'border:2px solid '+gw+';animation:pulse 1s ease-in-out infinite;opacity:0.75;"></div>')
    h=(
        '<div style="display:flex;flex-direction:column;align-items:center;'
        'background:linear-gradient(160deg,#0b0b18 0%,#141428 55%,#0b0b18 100%);'
        'border-radius:22px;padding:22px 16px 18px;min-height:500px;'
        'font-family:Segoe UI,sans-serif;position:relative;overflow:hidden;'
        'box-shadow:0 8px 40px rgba(0,0,0,0.6);">'
        '<div style="position:absolute;top:45%;left:50%;transform:translate(-50%,-50%);'
        'width:360px;height:360px;border-radius:50%;'
        'background:radial-gradient(circle,'+gw+'20 0%,transparent 68%);'
        'transition:background 1s;pointer-events:none;"></div>'
        '<div style="position:relative;width:290px;height:310px;margin-bottom:18px;">'
        '<div style="position:absolute;inset:-7px;border-radius:50% 50% 42% 42%;'
        'background:conic-gradient('+gw+','+gw+'55,'+gw+');'
        'animation:spin 5s linear infinite;opacity:0.55;transition:background 0.9s;"></div>'
        '<div style="position:absolute;inset:-3px;border-radius:50% 50% 42% 42%;background:#0b0b18;"></div>'
        '<div style="position:absolute;inset:0;border-radius:50% 50% 42% 42%;overflow:hidden;">'
        '<img id="avatarImg" src="data:image/jpeg;base64,'+AVATAR_B64+'"'
        ' style="width:100%;height:100%;object-fit:cover;object-position:center 8%;'
        'transition:filter 0.7s;" /></div>'
        '<canvas id="mouthCanvas" width="70" height="32"'
        ' style="position:absolute;bottom:23%;left:50%;transform:translateX(-50%);'
        'opacity:0.9;pointer-events:none;border-radius:50%;"></canvas>'
        '<div style="position:absolute;top:35%;left:33%;width:13%;height:7%;'
        'overflow:hidden;pointer-events:none;">'
        '<div style="width:100%;height:100%;animation:blink 4.5s ease-in-out infinite;"></div></div>'
        '<div style="position:absolute;top:35%;right:30%;width:13%;height:7%;'
        'overflow:hidden;pointer-events:none;">'
        '<div style="width:100%;height:100%;animation:blink 4.5s ease-in-out infinite 0.09s;"></div></div>'
        +pulse+
        '</div>'
        '<div style="display:flex;gap:10px;margin-bottom:12px;flex-wrap:wrap;justify-content:center;">'
        '<span style="background:rgba('+str(rv)+','+str(gv)+','+str(bv)+',0.18);'
        'border:1.5px solid '+gw+';color:'+gw+';'
        'padding:5px 16px;border-radius:20px;font-size:13px;font-weight:700;">'
        +el+'</span>'
        '<span style="background:rgba(255,255,255,0.06);border:1px solid rgba(255,255,255,0.2);'
        'color:#aaa;padding:5px 16px;border-radius:20px;font-size:13px;">'+sl+'</span></div>'
        '<div style="color:#fff;font-size:24px;font-weight:800;letter-spacing:3px;'
        'text-shadow:0 0 24px '+gw+',0 0 48px '+gw+'44;">JASON</div>'
        '<div style="color:#666;font-size:12px;margin-top:3px;letter-spacing:1px;">AI AVATAR ASSISTANT</div>'
        '<style>'
        '@keyframes spin{from{transform:rotate(0deg)}to{transform:rotate(360deg)}}'
        '@keyframes blink{0%,85%,100%{transform:scaleY(1)}92%{transform:scaleY(0.05)}}'
        '@keyframes pulse{0%,100%{opacity:0.3;transform:scale(1)}50%{opacity:0.85;transform:scale(1.05)}}'
        '@keyframes headbob{0%,100%{transform:translateY(0)}50%{transform:translateY(-3px)}}'
        '</style>'
    )
    js=(
        '<script>(function(){'
        'var c=document.getElementById("mouthCanvas");if(!c)return;'
        'var ctx=c.getContext("2d"),W=c.width,H=c.height;'
        'var st="'+state+'",em="'+emotion+'",fr=0,pi=0,lp=0;'
        'var ph=[0.05,0.45,0.8,0.3,0.9,0.15,0.65,0.2,0.85,0.4,0.1,0.6,0.75,0.25,0.05];'
        'var filt={'
        '"happy":"brightness(1.12) saturate(1.3) hue-rotate(5deg)",'
        '"excited":"brightness(1.18) saturate(1.5) hue-rotate(8deg)",'
        '"sad":"brightness(0.82) saturate(0.55) hue-rotate(-10deg)",'
        '"empathetic":"brightness(0.95) saturate(1.1)",'
        '"calm":"brightness(1.0) saturate(1.0)",'
        '"confident":"brightness(1.1) saturate(1.2)",'
        '"concerned":"brightness(0.88) saturate(0.75)",'
        '"thoughtful":"brightness(0.93) saturate(0.85)"'
        '};'
        'var img=document.getElementById("avatarImg");'
        'if(img&&filt[em])img.style.filter=filt[em];'
        'function dm(o){ctx.clearRect(0,0,W,H);'
        'var cx=W/2,cy=H/2+1,mw=W*0.70,mh=Math.max(2,o*H*0.85);'
        'ctx.beginPath();ctx.ellipse(cx,cy,mw/2+3,mh/2+4,0,0,Math.PI*2);'
        'ctx.fillStyle="rgba(50,15,5,0.6)";ctx.fill();'
        'ctx.beginPath();ctx.ellipse(cx,cy,mw/2,mh/2,0,0,Math.PI*2);'
        'ctx.fillStyle="rgba(10,2,1,0.92)";ctx.fill();'
        'if(o<0.2){ctx.beginPath();ctx.ellipse(cx,cy-mh/3.5,mw/3.8,2.5,0,0,Math.PI*2);'
        'ctx.fillStyle="rgba(200,140,120,0.4)";ctx.fill();}'
        'if(o>0.3){ctx.beginPath();ctx.ellipse(cx,cy,mw/2.5,mh/3.8,0,0,Math.PI);'
        'ctx.fillStyle="rgba(245,235,225,0.5)";ctx.fill();}}'
        'function an(){fr++;'
        'if(st==="talking"){'
        'if(fr-lp>=3){pi=(pi+1)%ph.length;lp=fr;}'
        'dm(Math.max(0.04,Math.min(1,ph[pi]+(Math.random()-0.5)*0.1)));}'
        'else if(st==="listening"){dm(0.06+Math.sin(Date.now()/200)*0.03);}'
        'else{dm(0.03);}requestAnimationFrame(an);}an();'
        '})();</script></div>'
    )
    return h+js

# =============================================================================
# GRADIO UI
# =============================================================================
def create_ui():
    os.makedirs("assets",exist_ok=True)
    os.makedirs("temp_audio",exist_ok=True)

    CSS = """
        body,.gradio-container{background:#0b0b18!important;}
        .gr-button-primary{background:linear-gradient(135deg,#6C63FF,#4fc3f7)!important;
          border:none!important;font-weight:700!important;font-size:15px!important;}
        .gr-button{background:#1a1a2e!important;color:#bbb!important;border:1px solid #2a2a3e!important;}
        footer{display:none!important;}
        label{color:#888!important;font-size:13px!important;}
    """

    def fmt(history,user,bot_reply):
        if _GR_MAJOR>=4:
            return history+[{"role":"user","content":user},{"role":"assistant","content":bot_reply}]
        return history+[(user,bot_reply)]

    # Gradio 6+ needs css in launch(), older in Blocks()
    try:
        demo=gr.Blocks(title="JASON — AI Avatar")
        _css_launch=True
    except Exception:
        demo=gr.Blocks(title="JASON — AI Avatar",css=CSS)
        _css_launch=False

    # SadTalker status banner
    _st_status = ("🎬 SadTalker ACTIVE — real lip-sync enabled"
                  if sad_talker.available else
                  "⚠ SadTalker not found — CSS animation fallback active")
    _st_color  = "#1a3a1a" if sad_talker.available else "#2a1a00"
    _st_border = "#4CAF50" if sad_talker.available else "#FF9800"

    with demo:
        cur_emotion=gr.State("calm")

        # SadTalker status banner
        gr.HTML(f'''<div style="
            background:{_st_color};border:1px solid {_st_border};
            color:{_st_border};border-radius:10px;padding:10px 18px;
            margin-bottom:8px;font-size:13px;font-family:monospace;">
            {_st_status}
        </div>''')

        with gr.Row(equal_height=True):
            with gr.Column(scale=5,min_width=330):
                # When SadTalker is active, video player shown; else HTML avatar
                if sad_talker.available:
                    avatar_video=gr.Video(
                        label="🎬 JASON (Live lip-sync)",
                        height=380, autoplay=True,
                        value=None)
                    avatar_html=gr.HTML(make_avatar_html("calm","idle"),visible=False)
                else:
                    avatar_video=gr.Video(visible=False,value=None)
                    avatar_html=gr.HTML(make_avatar_html("calm","idle"))

            with gr.Column(scale=3,min_width=260):
                gr.HTML('''<div style="padding:12px 0 8px;">
  <div style="color:#4fc3f7;font-size:22px;font-weight:800;letter-spacing:2px;">🤖 JASON</div>
  <div style="color:#555;font-size:12px;margin-top:3px;">Local AI · Voice & Text · 100% Offline</div>
</div>''')
                audio_in=gr.Audio(sources=["microphone"],type="filepath",label="🎤 Microphone")
                voice_btn=gr.Button("🎤 Send Voice",variant="primary",size="lg")
                status_box=gr.Textbox(
                    value="👋 Ready! Speak or type a message.",
                    label="Status",interactive=False,lines=2)
                audio_out=gr.Audio(label="🔊 JASON speaks",autoplay=True)

        try:
            chatbot=gr.Chatbot(type="messages",height=300,label="Conversation",bubble_full_width=False)
        except TypeError:
            chatbot=gr.Chatbot(height=300,label="Conversation")

        with gr.Row():
            text_in=gr.Textbox(placeholder="Type your message here…",
                               label="Your Message",scale=6,lines=1)
            send_btn=gr.Button("Send ➤",variant="primary",scale=1,size="lg")

        with gr.Accordion("🎭 Manual Emotion Override",open=False):
            emo_radio=gr.Radio(
                choices=["calm","happy","excited","sad","empathetic","confident","concerned","thoughtful"],
                value="calm",label="Force Avatar Emotion")

        # ── Core handler ─────────────────────────────────────────────────────
        def run(user_text,history,emotion):
            if history is None: history=[]
            if not user_text or not user_text.strip():
                yield history,make_avatar_html(emotion,"idle"),None,"❌ Empty.",None,emotion; return

            yield history,make_avatar_html(emotion,"thinking"),None,"⏳ Thinking…",None,emotion

            # 1. LLM
            reply=bot.get_ai_response(user_text)

            # 2. Emotion
            em=sentiment.get_emotion(user_text,reply)

            # 3. TTS
            audio=tts_gen.generate_audio(reply,em)

            # 4. SadTalker (if available)
            video=None
            if sad_talker.available and audio:
                yield history,make_avatar_html(em,"rendering"),None,"🎬 Rendering lip-sync video…",audio,em
                video=sad_talker.generate(bot.character_path, audio)
                sad_talker.cleanup()

            h2=fmt(history,user_text,reply)
            short=user_text[:40]+"…" if len(user_text)>40 else user_text
            st_txt=f"✅ {em.capitalize()} | '{short}'"
            if video:
                st_txt+=f" | 🎬 lip-sync ready"
            yield h2,make_avatar_html(em,"talking"),video,st_txt,audio,em

        def run_voice(audio_f,history,emotion):
            global _recognizer
            if audio_f is None:
                yield history,make_avatar_html(emotion,"idle"),None,"❌ No audio.",None,emotion; return
            yield history,make_avatar_html(emotion,"listening"),None,"🎤 Transcribing…",None,emotion
            if _recognizer is None: _recognizer=VoiceRecognizer()
            text=_recognizer.transcribe(audio_f)
            if not text or text.startswith("Error"):
                yield history,make_avatar_html(emotion,"idle"),None,f"❌ Could not understand. ({text or 'empty'})",None,emotion; return
            yield from run(text,history,emotion)

        def set_emotion(em):
            return make_avatar_html(em,"idle"),None,em

        outs=[chatbot,avatar_html,avatar_video,status_box,audio_out,cur_emotion]
        voice_btn.click(run_voice,inputs=[audio_in,chatbot,cur_emotion],outputs=outs)
        send_btn.click(run,inputs=[text_in,chatbot,cur_emotion],outputs=outs)
        text_in.submit(run,inputs=[text_in,chatbot,cur_emotion],outputs=outs)
        emo_radio.change(set_emotion,inputs=[emo_radio],
                         outputs=[avatar_html,avatar_video,cur_emotion])

    if _css_launch: return demo,CSS
    return demo,None

if __name__=="__main__":
    print("\n"+"="*55)
